  -- Deterministic lookup by seed
  FUNCTION GET_COMMENTS(
    p_seed IN VARCHAR2,
    p_max_len IN NUMBER DEFAULT 255
  ) RETURN VARCHAR2 DETERMINISTIC IS
    v_hash RAW(32);
    v_idx NUMBER;
  BEGIN
    v_hash := DBMS_CRYPTO.HASH(
      UTL_RAW.CAST_TO_RAW(NVL(p_seed, 'NULL')),
      DBMS_CRYPTO.HASH_SH256
    );
    v_idx := MOD(TO_NUMBER(SUBSTR(RAWTOHEX(v_hash), 1, 8), 'XXXXXXXX'), C_COUNT) + 1;
    RETURN SUBSTR(g_data(v_idx), 1, LEAST(p_max_len, 255));
  END GET_COMMENTS;

  -- Random lookup (non-deterministic)
  FUNCTION GET_COMMENTS_RANDOM(
    p_max_len IN NUMBER DEFAULT 255
  ) RETURN VARCHAR2 IS
    v_idx NUMBER;
  BEGIN
    v_idx := TRUNC(DBMS_RANDOM.VALUE(1, C_COUNT + 1));
    RETURN SUBSTR(g_data(v_idx), 1, LEAST(p_max_len, 255));
  END GET_COMMENTS_RANDOM;

  -- Index-based lookup
  FUNCTION GET_COMMENTS_BY_INDEX(
    p_index IN NUMBER,
    p_max_len IN NUMBER DEFAULT 255
  ) RETURN VARCHAR2 DETERMINISTIC IS
    v_idx NUMBER;
  BEGIN
    v_idx := MOD(ABS(NVL(p_index, 0)), C_COUNT) + 1;
    RETURN SUBSTR(g_data(v_idx), 1, LEAST(p_max_len, 255));
  END GET_COMMENTS_BY_INDEX;

  -- Count function
  FUNCTION GET_COUNT RETURN NUMBER DETERMINISTIC IS
  BEGIN
    RETURN C_COUNT;
  END GET_COUNT;

